'use client'

import React, { useState } from 'react'
import Link from 'next/link'

const links = [
  { label: 'Instagram', url: 'https://instagram.com/samlxzz', icon: '☷' },
  { label: 'TikTok', url: 'https://tiktok.com/@SaunKiziN', icon: '♫' },
  { label: 'YouTube', url: 'https://youtube.com/@saunkizin', icon: '▶' },
  { label: 'Twitch', url: 'https://twitch.tv/saunkizin', icon: '◉' },
  { label: 'Discord', url: 'https://discord.gg/SaunRKT', icon: '◆' },
  { label: 'Steam', url: 'https://steamcommunity.com/id/saunkizin/', icon: '★' },
]

export function LinkButtons() {
  const [soundEnabled, setSoundEnabled] = useState(false)
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null)


  const initAudio = () => {
    if (!audioContext) {
      const ctx = new AudioContext()
      setAudioContext(ctx)
    }
    setSoundEnabled((prev) => !prev)
  }

  const playHoverSound = () => {
    if (!soundEnabled || !audioContext) return

    const now = audioContext.currentTime
    const osc = audioContext.createOscillator()
    const gain = audioContext.createGain()

    osc.connect(gain)
    gain.connect(audioContext.destination)

    osc.frequency.setValueAtTime(800, now)
    osc.frequency.exponentialRampToValueAtTime(600, now + 0.05)
    gain.gain.setValueAtTime(0.05, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08)

    osc.start(now)
    osc.stop(now + 0.08)
  }

  const playClickSound = () => {
    if (!soundEnabled || !audioContext) return

    const now = audioContext.currentTime
    const osc = audioContext.createOscillator()
    const gain = audioContext.createGain()

    osc.connect(gain)
    gain.connect(audioContext.destination)

    osc.frequency.setValueAtTime(1200, now)
    osc.frequency.exponentialRampToValueAtTime(400, now + 0.1)
    gain.gain.setValueAtTime(0.08, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.12)

    osc.start(now)
    osc.stop(now + 0.12)
  }

  return (
    <section className="relative z-20 py-12 px-4 max-w-2xl mx-auto">
      <button
        onClick={initAudio}
        className="fixed bottom-6 right-6 z-50 p-2 rounded-lg border border-white/20 text-white/60 hover:text-white hover:border-white/60 transition-all duration-300 text-sm font-light tracking-widest focus-visible:outline-2 focus-visible:outline-white focus-visible:outline-offset-2"
        aria-label={soundEnabled ? 'Mute sounds' : 'Enable sounds'}
      >
        {soundEnabled ? '◆' : '◇'}
      </button>

      <div className="space-y-4">
        {links.map((link) => (
          <Link
            key={link.label}
            href={link.url}
            target={link.url !== '#' ? '_blank' : undefined}
            rel={link.url !== '#' ? 'noopener noreferrer' : undefined}
            className="link-button group block w-full px-8 py-4 border-2 border-white bg-black text-white text-center font-light tracking-wide"
            onMouseEnter={playHoverSound}
            onClick={playClickSound}
          >
            <span className="inline-flex items-center gap-3">
              <span className="text-lg opacity-70 group-hover:opacity-100 transition-opacity">
                {link.icon}
              </span>
              {link.label}
            </span>
          </Link>
        ))}
      </div>
    </section>
  )
}
